int gauss_elim(int m, int n, double matrix[m][n], double sol[m])
{

    for (int i = 0; i < m; i++) {


        int max_row = i;
        for (int r = i + 1; r < m; r++) {
            if (fabs(matrix[r][i]) > fabs(matrix[max_row][i])) {
                max_row = r;
            }
        }


        if (max_row != i) {
            for (int c = 0; c < n; c++) {
                double temp = matrix[i][c];
                matrix[i][c] = matrix[max_row][c];
                matrix[max_row][c] = temp;
            }
        }


        if (fabs(matrix[i][i]) < 1e-14) {
            fprintf(ferr, "ERROR: Pivot is zero (matrix is singular or nearly singular)\n");
            return -1;
        }


        for (int r = i + 1; r < m; r++) {
            double factor = matrix[r][i] / matrix[i][i];

            for (int c = i; c < n; c++) {
                matrix[r][c] -= factor * matrix[i][c];
            }
        }
    }


    for (int i = m - 1; i >= 0; i--) {

        sol[i] = matrix[i][n - 1];


        for (int c = i + 1; c < m; c++) {
            sol[i] -= matrix[i][c] * sol[c];
        }


        sol[i] /= matrix[i][i];
    }
    return 1;
}
